import base64
import json

def confirmAuth(headers):
    try:
        token_str = headers['AuthToken']
    except KeyError:
        return None
    try:
        decoded = base64.b64decode(token_str)
    except (TypeError, ValueError):
        return None
    try:
        decoded_str = decoded.decode('utf-8')
        token_data = json.loads(decoded_str)
    except (UnicodeDecodeError, json.JSONDecodeError):
        return None
    return token_data.get('data')

